import React, { useState } from 'react';
import { createRoot } from 'react-dom/client';
import { Button } from '../design-system/Button/Button';
import { Card } from '../design-system/Card/Card';
import { Badge } from '../design-system/Badge/Badge';
import { Input } from '../design-system/Input/Input';
import { Select } from '../design-system/Select/Select';
import '../theme/variables.css';

interface BillingCode {
  code: string;
  description: string;
  fee: number;
  rationale: string;
  confidence: number;
  primary_reason: boolean;
}

const AI_SERVICE_URL = 'http://localhost:8000';

function BillingSuggester() {
  const [diagnosis, setDiagnosis] = useState('');
  const [encounterType, setEncounterType] = useState('visit');
  const [age, setAge] = useState('');
  const [notes, setNotes] = useState('');
  const [suggestions, setSuggestions] = useState<BillingCode[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [accepted, setAccepted] = useState<Set<string>>(new Set());
  const [isMock, setIsMock] = useState(false);

  const handleSuggest = async () => {
    setError(null);
    setLoading(true);
    try {
      const res = await fetch(`${AI_SERVICE_URL}/api/v1/billing/suggest`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          diagnosis,
          encounter_type: encounterType,
          patient_age: age ? parseInt(age) : undefined,
          provider_notes: notes,
        }),
      });
      if (!res.ok) throw new Error(`Server error: ${res.status}`);
      const data = await res.json();
      setSuggestions(data.suggestions);
      setIsMock(data.mock || false);
      setAccepted(new Set());
    } catch (e: any) {
      setError(e.message || 'Failed to get billing suggestions');
    } finally {
      setLoading(false);
    }
  };

  const toggleAccept = (code: string) => {
    setAccepted(prev => {
      const next = new Set(prev);
      next.has(code) ? next.delete(code) : next.add(code);
      return next;
    });
  };

  const acceptAll = () => setAccepted(new Set(suggestions.map(s => s.code)));
  const clearAll = () => setAccepted(new Set());

  const totalAccepted = suggestions.filter(s => accepted.has(s.code));
  const totalFee = totalAccepted.reduce((sum, s) => sum + s.fee, 0);

  const getConfidenceColor = (c: number): 'success' | 'warning' | 'error' => {
    if (c >= 0.85) return 'success';
    if (c >= 0.6) return 'warning';
    return 'error';
  };

  return (
    <div style={{ maxWidth: 700, margin: '0 auto', padding: 'var(--spacing-4)' }}>
      <Card title="AI Billing Code Suggester">
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--spacing-3)' }}>
          <Input label="Diagnosis" value={diagnosis} onChange={e => setDiagnosis(e.target.value)} placeholder="e.g. Type 2 diabetes, hypertension" />
          <Select label="Encounter Type" value={encounterType} onChange={e => setEncounterType(e.target.value)}
            options={[{value:'visit',label:'In-person visit'},{value:'phone',label:'Telephone'},{value:'home',label:'Home visit'}]} />
          <Input label="Patient Age" value={age} onChange={e => setAge(e.target.value)} placeholder="Optional" type="number" />
        </div>
        <div style={{ marginTop: 'var(--spacing-2)' }}>
          <Button onClick={handleSuggest} disabled={diagnosis.length < 3 || loading}>
            {loading ? 'Suggesting...' : 'Suggest Billing Codes'}
          </Button>
        </div>
        {error && <div style={{ marginTop: 'var(--spacing-3)', padding: 'var(--spacing-3)', background: 'var(--color-error-light)', borderRadius: 'var(--radius-md)', color: 'var(--color-error)', fontSize: 'var(--font-size-sm)' }}>{error}</div>}
        {isMock && <div style={{ marginTop: 'var(--spacing-2)' }}><Badge variant="warning">Offline mode (mock suggestions)</Badge></div>}
      </Card>

      {suggestions.length > 0 && (
        <Card title="Suggested Codes" style={{ marginTop: 'var(--spacing-4)' }}>
          <div style={{ display: 'flex', gap: 'var(--spacing-2)', marginBottom: 'var(--spacing-3)' }}>
            <Button size="sm" variant="secondary" onClick={acceptAll}>Accept All</Button>
            <Button size="sm" variant="ghost" onClick={clearAll}>Clear</Button>
            {totalAccepted.length > 0 && (
              <span style={{ fontSize: 'var(--font-size-sm)', color: 'var(--color-success)', fontWeight: 600, alignSelf: 'center' }}>
                {totalAccepted.length} code{totalAccepted.length > 1 ? 's' : ''} — ${totalFee.toFixed(2)}
              </span>
            )}
          </div>

          {suggestions.map((s, i) => (
            <div key={s.code} style={{
              display: 'flex', alignItems: 'flex-start', gap: 'var(--spacing-3)',
              padding: 'var(--spacing-3)', marginBottom: 'var(--spacing-2)',
              border: accepted.has(s.code) ? '2px solid var(--color-success)' : '1px solid var(--color-neutral-200)',
              borderRadius: 'var(--radius-md)', backgroundColor: accepted.has(s.code) ? 'var(--color-success-light)' : '#fff',
              cursor: 'pointer', transition: 'border-color var(--transition-fast)',
            }} onClick={() => toggleAccept(s.code)}>
              <input type="checkbox" checked={accepted.has(s.code)} onChange={() => {}} style={{ marginTop: 2 }} />
              <div style={{ flex: 1 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--spacing-2)', marginBottom: 2 }}>
                  <strong style={{ fontSize: 'var(--font-size-lg)' }}>{s.code}</strong>
                  <Badge variant="neutral">{s.description}</Badge>
                  <Badge variant={getConfidenceColor(s.confidence)}>{Math.round(s.confidence * 100)}%</Badge>
                </div>
                <div style={{ fontSize: 'var(--font-size-sm)', color: 'var(--color-neutral-500)' }}>{s.rationale}</div>
              </div>
              <div style={{ fontWeight: 700, fontSize: 'var(--font-size-lg)', color: 'var(--color-primary-700)', minWidth: 60, textAlign: 'right' }}>
                ${s.fee.toFixed(2)}
              </div>
            </div>
          ))}

          {totalAccepted.length > 0 && (
            <div style={{ marginTop: 'var(--spacing-4)', padding: 'var(--spacing-3)', background: 'var(--color-primary-50)', borderRadius: 'var(--radius-md)', textAlign: 'right' }}>
              <span style={{ fontSize: 'var(--font-size-sm)', color: 'var(--color-neutral-500)' }}>Total billing: </span>
              <strong style={{ fontSize: 'var(--font-size-xl)', color: 'var(--color-primary-700)' }}>${totalFee.toFixed(2)}</strong>
            </div>
          )}
        </Card>
      )}
    </div>
  );
}

const el = document.getElementById('billing-root');
if (el) createRoot(el).render(<BillingSuggester />);
